import React from "react";
import { Link, useLocation } from "react-router-dom";

type BookingState = {
  booking?: {
    _id: string;
    seats: string[];
    totalPrice: number;
    createdAt: string;
  };
  busName?: string;
};

const Confirmation: React.FC = () => {
  const location = useLocation();
  const state = location.state as BookingState;

  if (!state?.booking) {
    return (
      <div className="page-container">
        <h2>No booking found</h2>
        <Link to="/">Back to home</Link>
      </div>
    );
  }

  return (
    <div className="page-container">
      <h2>Booking Confirmed</h2>
      <div className="card">
        <p>Bus: {state.busName}</p>
        <p>Booking ID: {state.booking._id}</p>
        <p>Seats: {state.booking.seats.join(", ")}</p>
        <p>Total Paid: INR {state.booking.totalPrice}</p>
        <p>Booked At: {new Date(state.booking.createdAt).toLocaleString()}</p>
      </div>
      <Link to="/">Book another trip</Link>
    </div>
  );
};

export default Confirmation;
